function maxDepth(root) {
  if (!root) return 0;
  return 1 + Math.max(maxDepth(root.left), maxDepth(root.right));
}

function invertTree(root) {
  if (!root) return null;
  [root.left, root.right] = [invertTree(root.right), invertTree(root.left)];
  return root;
}

function inorder(root, out = []) {
  if (!root) return out;
  inorder(root.left, out);
  out.push(root.val);
  inorder(root.right, out);
  return out;
}

function levelOrder(root) {
  if (!root) return [];
  const res = [], queue = [root];
  while (queue.length) {
    const size = queue.length;
    const level = [];
    for (let i = 0; i < size; i++) {
      const node = queue.shift();
      level.push(node.val);
      if (node.left) queue.push(node.left);
      if (node.right) queue.push(node.right);
    }
    res.push(level);
  }
  return res;
}

function isValidBST(root, low = -Infinity, high = Infinity) {
  if (!root) return true;
  if (root.val <= low || root.val >= high) return false;
  return isValidBST(root.left, low, root.val) &&
         isValidBST(root.right, root.val, high);
}

function lowestCommonAncestor(root, p, q) {
  let node = root;
  while (node) {
    if (p.val < node.val && q.val < node.val) node = node.left;
    else if (p.val > node.val && q.val > node.val) node = node.right;
    else return node;
  }
}

function numIslands(grid) {
  const rows = grid.length, cols = grid[0].length;
  let count = 0;
  function dfs(r, c) {
    if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] === '0') return;
    grid[r][c] = '0';
    dfs(r + 1, c); dfs(r - 1, c); dfs(r, c + 1); dfs(r, c - 1);
  }
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (grid[r][c] === '1') { count++; dfs(r, c); }
    }
  }
  return count;
}

function canFinish(numCourses, prerequisites) {
  const indegree = new Array(numCourses).fill(0);
  const adj = Array.from({ length: numCourses }, () => []);
  for (const [course, pre] of prerequisites) {
    adj[pre].push(course);
    indegree[course]++;
  }
  const queue = [];
  for (let i = 0; i < numCourses; i++) if (indegree[i] === 0) queue.push(i);
  let seen = 0;
  while (queue.length) {
    const node = queue.shift();
    seen++;
    for (const next of adj[node]) {
      if (--indegree[next] === 0) queue.push(next);
    }
  }
  return seen === numCourses;
}

function cloneGraph(node) {
  if (!node) return null;
  const clones = new Map();
  clones.set(node, new Node(node.val));
  const queue = [node];
  while (queue.length) {
    const cur = queue.shift();
    for (const nb of cur.neighbors) {
      if (!clones.has(nb)) {
        clones.set(nb, new Node(nb.val));
        queue.push(nb);
      }
      clones.get(cur).neighbors.push(clones.get(nb));
    }
  }
  return clones.get(node);
}

function shortestPath(grid, start, target) {
  const rows = grid.length, cols = grid[0].length;
  const queue = [[start[0], start[1], 0]];
  const seen = new Set([start[0] + ',' + start[1]]);
  while (queue.length) {
    const [r, c, d] = queue.shift();
    if (r === target[0] && c === target[1]) return d;
    for (const [dr, dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
      const nr = r + dr, nc = c + dc;
      if (nr >= 0 && nc >= 0 && nr < rows && nc < cols &&
          grid[nr][nc] === 0 && !seen.has(nr + ',' + nc)) {
        seen.add(nr + ',' + nc);
        queue.push([nr, nc, d + 1]);
      }
    }
  }
  return -1;
}

function gameOfLife(board) {
  const rows = board.length, cols = board[0].length;
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      let live = 0;
      for (let dr = -1; dr <= 1; dr++) {
        for (let dc = -1; dc <= 1; dc++) {
          if (dr === 0 && dc === 0) continue;
          const nr = r + dr, nc = c + dc;
          if (nr >= 0 && nc >= 0 && nr < rows && nc < cols) {
            live += board[nr][nc] & 1; // read current state from bit 0
          }
        }
      }
      if (board[r][c] & 1) {
        if (live === 2 || live === 3) board[r][c] |= 2; // survives
      } else if (live === 3) {
        board[r][c] |= 2; // born
      }
    }
  }
  for (let r = 0; r < rows; r++)
    for (let c = 0; c < cols; c++)
      board[r][c] >>= 1; // next state becomes current
}

class Trie {
  constructor() { this.root = {}; }
  insert(word) {
    let node = this.root;
    for (const ch of word) node = (node[ch] ??= {});
    node.end = true;
  }
  autocomplete(prefix) {
    let node = this.root;
    for (const ch of prefix) {
      node = node[ch];
      if (!node) return [];
    }
    const out = [];
    (function dfs(n, path) {
      if (n.end) out.push(prefix + path);
      for (const ch in n) if (ch !== 'end') dfs(n[ch], path + ch);
    })(node, '');
    return out;
  }
}

function countComponents(n, edges) {
  const parent = Array.from({ length: n }, (_, i) => i);
  function find(x) {
    while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
    return x;
  }
  let count = n;
  for (const [a, b] of edges) {
    const ra = find(a), rb = find(b);
    if (ra !== rb) { parent[ra] = rb; count--; }
  }
  return count;
}

class MinHeap {
  constructor() { this.a = []; }
  size() { return this.a.length; }
  peek() { return this.a[0]; }
  push(v) {
    const a = this.a; a.push(v); let i = a.length - 1;
    while (i > 0) { const p = (i - 1) >> 1; if (a[p] <= a[i]) break; [a[p], a[i]] = [a[i], a[p]]; i = p; }
  }
  pop() {
    const a = this.a, top = a[0], last = a.pop();
    if (a.length) { a[0] = last; let i = 0;
      for (;;) { let l = 2*i+1, r = 2*i+2, s = i;
        if (l < a.length && a[l] < a[s]) s = l;
        if (r < a.length && a[r] < a[s]) s = r;
        if (s === i) break; [a[s], a[i]] = [a[i], a[s]]; i = s; } }
    return top;
  }
}
function findKthLargest(nums, k) {
  const h = new MinHeap();
  for (const n of nums) { h.push(n); if (h.size() > k) h.pop(); }
  return h.peek();
}
